const axios = require('axios');
const cheerio = require('cheerio');

async function fetchMetadata(url) {
  try {
    const response = await axios.get(url, { timeout: 5000 });
    if (response.status !== 200) {
      throw new Error(`Failed to retrieve metadata. Status code: ${response.status}`);
    }

    const $ = cheerio.load(response.data);
    const metaTags = $('meta');

    const title = $('title').text().trim();
    const description = metaTags.filter((index, tag) => $(tag).attr('name') === 'description').attr('content');
    const openGraphImage = metaTags.filter((index, tag) => $(tag).attr('property') === 'og:image').attr('content');
    const openGraphTitle = metaTags.filter((index, tag) => $(tag).attr('property') === 'og:title').attr('content');
    const openGraphDescription = metaTags.filter((index, tag) => $(tag).attr('property') === 'og:description').attr('content');

    return {
      title,
      description,
      openGraphImage,
      openGraphTitle,
      openGraphDescription
    };
  } catch (error) {
    throw new Error(`Failed to fetch metadata: ${error.message}`);
  }
}

module.exports = { fetchMetadata };

// Example usage:
